const complaint = $input.first().json;
const input = $('Webhook Trigger').first().json;
const phone = complaint.phone || '';
const statusMessages = {
  'IN_PROGRESS': '🔄 স্ট্যাটাস আপডেট | Status Update

🎫 টিকেট: ' + complaint.ticketNo + '
📌 স্ট্যাটাস: 🟡 IN_PROGRESS | চলমান

আপনার অভিযোগের কাজ শুরু হয়েছে।
Work on your complaint has started.',
  'RESOLVED': '✅ অভিযোগ সমাধান | Complaint Resolved

🎫 টিকেট: ' + complaint.ticketNo + '
📝 সমাধান: ' + (complaint.resolution || 'Resolved') + '

আপনার অভিযোগ সমাধান করা হয়েছে।
Your complaint has been resolved.

⭐ আপনার অভিজ্ঞতা রেট করুন (Reply 1-5):
1 = খুব খারাপ | Very Poor
2 = খারাপ | Poor
3 = গড় | Average
4 = ভালো | Good
5 = খুব ভালো | Excellent',
  'REJECTED': '❌ অভিযোগ বাতিল | Complaint Rejected

🎫 টিকেট: ' + complaint.ticketNo + '

বিস্তারিত জানতে আপনার ব্লক অফিসে যোগাযোগ করুন।
Contact your block office for details.',
  'OPEN': '🎫 আপনার অভিযোগ গ্রহণ করা হয়েছে | Your complaint has been received

🎫 টিকেট: ' + complaint.ticketNo + '
📌 বিষয়: ' + complaint.issue + '

শীঘ্রই ব্যবস্থা নেওয়া হবে।
Action will be taken soon.'
};
const slaMessage = '⚠️ SLA লঙ্ঘন বিজ্ঞপ্তি | SLA Breach Notice

🎫 টিকেট: ' + complaint.ticketNo + '
🔴 আপনার অভিযোগ এসক্যালেট করা হয়েছে
Your complaint has been escalated.';

let message = '';
if (input.source === 'sla_breach_batch') {
  message = slaMessage;
} else if (input.status) {
  message = statusMessages[input.status] || statusMessages['OPEN'];
}

return [{ json: { phone, message, ticketNo: complaint.ticketNo } }];

const input = $('Officer Webhook').first().json;
const complaint = $input.first().json;
const officers = Array.isArray(complaint.users) ? complaint.users : [];
const assignMsg = '🔔 নতুন অভিযোগ নিয়োগ | New Complaint Assigned

🎫 টিকেট: (pending)
📌 বিষয়: (pending)
📍 ব্লক: (pending)

অনুগ্রহ করে শীঘ্র ব্যবস্থা নিন।
Please take action at the earliest.';
const escMsg = '🚨 এসক্যালেশন সতর্কতা | Escalation Alert

🎫 টিকেট: (pending)
⬆️ জরুরিতা পরিবর্তন: ' + (input.previousUrgency||'') + ' → ' + (input.newUrgency||'') + '
⏰ কারণ: ' + (input.reason||'SLA Breach') + '

এটি একটি উচ্চ-অগ্রাধিকার এসক্যালেশন। অবিলম্বে ব্যবস্থা নিন।
This is a high-priority escalation. Take immediate action.';

let message = assignMsg;
if (input.source === 'urgency_escalation') message = escMsg;

return [{ json: { message, officers, complaintId: input.complaintId } }];
